SELECT algorithm_name, algorithm_complexity
FROM compression_algorithms
ORDER BY algorithm_complexity DESC;

SELECT image_name
FROM test_images
WHERE image_size > 1.3;

SELECT session_name, start_date
FROM evaluation_sessions
ORDER BY session_name;

SELECT session_name, description
FROM evaluation_sessions
WHERE session_status = 'active';

SELECT AVG(image_size) AS average_image_size
FROM test_images
WHERE upload_date > '2023-01-01';

SELECT algorithm_name
FROM compression_algorithms
ORDER BY algorithm_name ASC;

SELECT setting_name, setting_value, setting_type
FROM compression_settings
WHERE setting_type = 'compression ratio';
